import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useAppStore } from "../store/appStore";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const fmtBps = (v) => v == null ? "--" : `${v.toFixed(1)} bps`;
const fmtPct = (v) => v == null ? "--" : `${(v * 100).toFixed(1)}%`;
const fmtMs  = (v) => v == null ? "--" : `${v.toFixed(0)}ms`;
const fmtUsd = (v) => v == null ? "--" : `$${v.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;

const slippageTone = (v) => {
  if (v == null) return "blue";
  if (Math.abs(v) < 1) return "green";
  if (Math.abs(v) < 3) return "amber";
  return "red";
};

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, tone = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${tone}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── latency bucket labels ───────────────────────────── */
const LATENCY_BUCKETS = ["0-10ms", "10-25ms", "25-50ms", "50-100ms", "100-250ms", "250ms+"];

/* ── main page ───────────────────────────────────────── */
export default function ExecutionQuality() {
  const { state } = useAppStore();

  const { data: eqData, loading } = usePoll(
    async () => { const r = await http.get("/v2/execution-quality?days=30"); return r.data; },
    { intervalMs: 10000, enabled: !state.offlineMode }
  );

  // If the API returned an error in the summary, treat summary as null
  const rawSummary = eqData?.summary ?? null;
  const summary   = (rawSummary && rawSummary.error) ? null : rawSummary;
  const byVenue   = eqData?.by_venue ?? [];
  const hourly    = eqData?.hourly_slippage ?? [];
  const tca       = eqData?.tca ?? [];
  const compliance = eqData?.compliance ?? null;

  /* derive latency histogram from summary or build from hourly */
  const latencyBuckets = summary?.latency_histogram ?? [];

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Execution Quality</h1>
            <div className="v2-muted">Loading execution data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  const totalFills = summary?.total_fills ?? byVenue.reduce((a, v) => a + (v.fills || 0), 0);

  return (
    <>
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Execution Quality</h1>
          <div className="v2-muted">Slippage analysis, fill ratios, latency histograms, transaction cost analysis.</div>
        </div>
        <div className="v2-row">
          <span className="v2-pill">Live</span>
          <span className="v2-pill v2-mono">{totalFills.toLocaleString()} fills</span>
        </div>
      </div>

      {/* ── Top Stats ──────────────────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat
          label="Avg Slippage"
          value={summary ? fmtBps(summary.avg_slippage_bps) : "--"}
          tone={summary ? slippageTone(summary.avg_slippage_bps) : "blue"}
          sub={summary ? `${totalFills} fills analysed` : "Waiting for fill data"}
        />
        <Stat
          label="Fill Rate"
          value={summary ? fmtPct(summary.fill_rate) : "--"}
          tone={summary ? (summary.fill_rate > 0.95 ? "green" : summary.fill_rate > 0.85 ? "amber" : "red") : "blue"}
          sub={summary ? "Orders fully filled" : "Waiting for fill data"}
        />
        <Stat
          label="Avg Latency"
          value={summary ? fmtMs(summary.avg_latency_ms) : "--"}
          tone={summary ? (summary.avg_latency_ms < 50 ? "green" : summary.avg_latency_ms < 150 ? "amber" : "red") : "blue"}
          sub={summary ? "Order-to-fill" : "Waiting for fill data"}
        />
        <Stat
          label="Cost Savings"
          value={summary ? fmtUsd(summary.cost_savings) : "--"}
          tone={summary ? "green" : "blue"}
          sub={summary ? "vs arrival price" : "Waiting for fill data"}
        />
      </div>

      <div className="v2-grid">
        {/* ── Slippage Analysis Table (hourly) ────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Hourly Slippage Analysis</div>
          {hourly.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Slippage Data" message="Slippage analysis will appear when order fill data is available from the API." />
          ) : (
            <>
              {/* bar chart */}
              <div style={{ display: "flex", alignItems: "flex-end", gap: 4, height: 80, marginTop: 12 }}>
                {hourly.map((h, i) => {
                  const maxSlip = Math.max(1, ...hourly.map(x => Math.abs(x.avg_slippage_bps ?? x.slippage ?? 0)));
                  const val = Math.abs(h.avg_slippage_bps ?? h.slippage ?? 0);
                  const pct = (val / maxSlip) * 100;
                  const isNeg = (h.avg_slippage_bps ?? h.slippage ?? 0) < 0;
                  return (
                    <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center" }}>
                      <div style={{
                        width: "100%", height: `${pct}%`, minHeight: val > 0 ? 3 : 0, borderRadius: 6,
                        background: isNeg
                          ? "linear-gradient(180deg, rgba(110,240,180,0.7), rgba(110,240,180,0.2))"
                          : val > 2
                          ? "linear-gradient(180deg, rgba(255,120,120,0.7), rgba(255,120,120,0.2))"
                          : "linear-gradient(180deg, rgba(150,190,255,0.6), rgba(150,190,255,0.15))",
                      }} title={`${h.hour ?? i}:00 — ${(h.avg_slippage_bps ?? h.slippage ?? 0).toFixed(1)} bps`} />
                    </div>
                  );
                })}
              </div>
              <div className="v2-row" style={{ justifyContent: "space-between", marginTop: 8 }}>
                <span className="v2-muted" style={{ fontSize: 10 }}>00:00</span>
                <span className="v2-muted" style={{ fontSize: 10 }}>12:00</span>
                <span className="v2-muted" style={{ fontSize: 10 }}>23:00</span>
              </div>
              {/* table */}
              <div className="v2-table" style={{ marginTop: 12 }}>
                <div className="v2-thead" style={{ gridTemplateColumns: "80px 100px 80px 80px 80px" }}>
                  <span>Hour</span>
                  <span>Avg Slippage</span>
                  <span>Fills</span>
                  <span>Max Slip</span>
                  <span>Min Slip</span>
                </div>
                {hourly.slice(0, 12).map((h, i) => (
                  <div key={i} className="v2-tr" style={{ gridTemplateColumns: "80px 100px 80px 80px 80px" }}>
                    <span className="v2-mono">{String(h.hour ?? i).padStart(2, "0")}:00</span>
                    <span className={`v2-mono v2-${slippageTone(h.avg_slippage_bps ?? h.slippage)}`}>
                      {fmtBps(h.avg_slippage_bps ?? h.slippage)}
                    </span>
                    <span className="v2-mono">{h.fills ?? h.count ?? "--"}</span>
                    <span className="v2-mono v2-muted">{fmtBps(h.max_slippage_bps ?? h.max)}</span>
                    <span className="v2-mono v2-muted">{fmtBps(h.min_slippage_bps ?? h.min)}</span>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>

        {/* ── Fill Rate by Venue ──────────────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Fill Rate by Venue</div>
          {byVenue.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Venue Fill Data" message="Fill rate by venue will appear when venue-level fill data is available." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {byVenue.map(v => {
                const rate = v.fill_rate ?? (v.fills && v.orders ? v.fills / v.orders : 0);
                const pct = rate * 100;
                const color = pct > 95 ? "var(--v2-green)" : pct > 85 ? "var(--v2-amber)" : "var(--v2-red)";
                return (
                  <div key={v.venue} style={{ marginBottom: 12 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
                      <span>{v.venue}</span>
                      <span className="v2-mono" style={{ color }}>{pct.toFixed(1)}%</span>
                    </div>
                    <div style={{ height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{ height: "100%", width: `${pct}%`, borderRadius: 6, background: color, transition: "width 0.4s ease" }} />
                    </div>
                    <div className="v2-muted" style={{ fontSize: 10, marginTop: 4 }}>
                      {v.fills ?? "--"} fills / {v.orders ?? "--"} orders
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Latency Histogram ──────────────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Latency Distribution</div>
          {latencyBuckets.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Latency Distribution" message="Latency histogram will appear when order timing data is available." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {latencyBuckets.map((b, i) => {
                const label = b.label ?? LATENCY_BUCKETS[i] ?? `Bucket ${i + 1}`;
                const count = b.count ?? b;
                const maxCount = Math.max(1, ...latencyBuckets.map(x => x.count ?? 0));
                const pct = (count / maxCount) * 100;
                return (
                  <div key={i} style={{ marginBottom: 8 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
                      <span>{label}</span>
                      <span className="v2-mono">{count.toLocaleString()}</span>
                    </div>
                    <div style={{ height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{
                        height: "100%", width: `${pct}%`, borderRadius: 6, transition: "width 0.4s ease",
                        background: i < 2 ? "var(--v2-green)" : i < 4 ? "var(--v2-amber)" : "var(--v2-red)",
                      }} />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Transaction Cost Analysis ──────────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Transaction Cost Analysis</div>
          {tca.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No TCA Data" message="Transaction cost analysis will appear when strategy-level cost data is available." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "160px 100px 100px 100px 100px 100px" }}>
                <span>Strategy</span>
                <span>Slippage</span>
                <span>Commission</span>
                <span>Market Impact</span>
                <span>Total Cost</span>
                <span>Net Alpha</span>
              </div>
              {tca.map(row => {
                const totalCost = (row.slippage_bps ?? 0) + (row.commission_bps ?? 0) + (row.market_impact_bps ?? 0);
                const netAlpha = (row.gross_alpha_bps ?? 0) - totalCost;
                return (
                  <div key={row.strategy} className="v2-tr" style={{ gridTemplateColumns: "160px 100px 100px 100px 100px 100px" }}>
                    <span style={{ fontWeight: 600 }}>{row.strategy}</span>
                    <span className="v2-mono v2-muted">{fmtBps(row.slippage_bps)}</span>
                    <span className="v2-mono v2-muted">{fmtBps(row.commission_bps)}</span>
                    <span className="v2-mono v2-muted">{fmtBps(row.market_impact_bps)}</span>
                    <span className={`v2-mono v2-${totalCost > 5 ? "red" : "amber"}`}>{fmtBps(totalCost)}</span>
                    <span className={`v2-mono v2-${netAlpha > 0 ? "green" : "red"}`}>{fmtBps(netAlpha)}</span>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Best Execution Compliance ──────────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Best Execution Compliance</div>
          {!compliance ? (
            <V2EmptyState icon={"\u29C6"} title="No Compliance Data" message="Best execution compliance metrics will appear when execution data is available." />
          ) : (
            <div style={{ marginTop: 8 }}>
              {/* summary row */}
              <div style={{ display: "flex", gap: 20, flexWrap: "wrap", marginBottom: 16 }}>
                {[
                  { label: "NBBO Compliance", value: fmtPct(compliance.nbbo_rate), tone: compliance.nbbo_rate > 0.95 ? "green" : "amber" },
                  { label: "Price Improvement", value: fmtPct(compliance.price_improvement_rate), tone: "green" },
                  { label: "Internalized %", value: fmtPct(compliance.internalized_rate), tone: "blue" },
                  { label: "Audit Score", value: compliance.audit_score != null ? `${compliance.audit_score}/100` : "--", tone: compliance.audit_score > 90 ? "green" : "amber" },
                ].map(m => (
                  <div key={m.label} style={{ flex: "1 1 140px" }}>
                    <div className="v2-muted" style={{ fontSize: 11, marginBottom: 4 }}>{m.label}</div>
                    <div className={`v2-mono v2-${m.tone}`} style={{ fontSize: 16, fontWeight: 700 }}>{m.value}</div>
                  </div>
                ))}
              </div>
              {/* compliance checks */}
              {(compliance.checks ?? []).length > 0 && (
                <div className="v2-table">
                  <div className="v2-thead" style={{ gridTemplateColumns: "200px 100px 1fr" }}>
                    <span>Check</span>
                    <span>Status</span>
                    <span>Detail</span>
                  </div>
                  {compliance.checks.map((c, i) => (
                    <div key={i} className="v2-tr" style={{ gridTemplateColumns: "200px 100px 1fr" }}>
                      <span>{c.name}</span>
                      <span className={`v2-${c.passed ? "green" : "red"}`} style={{ fontWeight: 600, fontSize: 11, textTransform: "uppercase" }}>
                        {c.passed ? "PASS" : "FAIL"}
                      </span>
                      <span className="v2-muted">{c.detail ?? "--"}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
